// Parse build_weather_rules.py output and surface key signals
const item = $input.first().json;
const raw = typeof item === 'string' ? item : (item.stdout ?? '');
let report = {};
try { report = JSON.parse(raw); } catch (e) { report = {}; }

const stats = report.stats || {};
const buildReport = report.report || {};
const exitFailed = Number(item.exitCode || 0) !== 0 || Boolean(item.error);
const errors = (stats.errors || 0) + (exitFailed && !stats.errors ? 1 : 0);

return {
  json: {
    stats: stats,
    total: stats.total || 0,
    original: stats.original || 0,
    added: stats.added || 0,
    errors,
    has_failures: errors > 0,
    backup_path: buildReport.backup_path || null,
    output_path: buildReport.output_path || null,
    written: Boolean(buildReport.written),
    temp_ranges_added: buildReport.temp_ranges_added || [],
    pty_meaning_filled: buildReport.pty_meaning_filled || [],
    kma_fields_added: buildReport.kma_fields_added || [],
    required_filled: buildReport.required_filled || []
  }
};

// Console-only success log - Slack HTTP Request 노드 분기 외부에서도 동작
const data = $input.first().json;
console.log('[weather-rules-build] OK', JSON.stringify({
  total: data.total,
  original: data.original,
  added: data.added,
  temp_ranges_added: data.temp_ranges_added,
  pty_meaning_filled: data.pty_meaning_filled,
  required_filled: data.required_filled
}));
return { json: { logged: true, summary: 'success', ...data } };

// SLACK_WEBHOOK_URL 미설정 시 console.log 로 대체
const data = $input.first().json;
console.log('[weather-rules-build] FAIL (no Slack webhook configured)', JSON.stringify({
  errors: data.errors,
  total: data.total,
  output_path: data.output_path,
  backup_path: data.backup_path
}));
return { json: { logged: true, channel: 'console', ...data } };
